    # Function to greet a user in multiple South African Indian languages
    def greet_user(name, language='english'):
        greetings = {
            'english': f'Hello, {name}! How are you today?',
            'afrikaans': f'Haai, {name}! Hoe gaan dit?',
            'zulu': f'Sawubona, {name}! Unjani?',
            'hindi': f'Namaste, {name}! Aap kaise hain?',
            'tamil': f'Vanakkam, {name}! Eppadi irukkeenga?'
        }
        return greetings.get(language.lower(), greetings['english'])

